#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
using namespace std;
il ll read()
{
    ll x=0,f=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
void write(ll x)
{
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e6+5,MOD=1e9+7;
vector<ll>a[MAXN];
ll f[MAXN],n,ct[MAXN];
int main(void)
{
    n=read();
    FOR(i,1,n-1)
    {
        int u=read(),v=read();
        a[u].pb(v);
    }
    f[0]=1;
    queue<ll> q;
    q.push(0);
    ll maxn=0;  
    ct[1]=1;
    while(q.size())
    {
        ll u=q.front();
        q.pop();
        FOI(v,a[u])
        {
            f[v]=f[u]+1;
            ++ct[f[v]];
            maxn=max(maxn,f[v]);
            q.push(v);
        }
    }
    ll ans=0;
    FOR(i,1,maxn)ans=(ans+ct[i]*(ct[i]-1)/2);
    FOR(i,1,maxn-1)ans=(ans+ct[i]*ct[i+1]);
    n=ans-n+1;
    ll res=1,a=2;
    while(n)
    {
        if(n&1)
        {
            res=(res*a)%MOD;
        }
        a=(a*a)%MOD;
        n>>=1;
    }
    write(res);
    return false;
}
